/**
 * @sam-ai/integration - AI Provider Adapter Interface
 * Abstract AI/LLM operations for portability
 */

import { z } from 'zod';

// ============================================================================
// MESSAGE TYPES
// ============================================================================

/**
 * Message role in conversation
 */
export type MessageRole = 'system' | 'user' | 'assistant' | 'function' | 'tool';

/**
 * Chat message
 */
export interface ChatMessage {
  role: MessageRole;
  content: string;
  name?: string;
  toolCallId?: string;
  toolCalls?: ToolCall[];
}

/**
 * Tool/function call
 */
export interface ToolCall {
  id: string;
  type: 'function';
  function: {
    name: string;
    arguments: string;
  };
}

/**
 * Tool definition for function calling
 */
export interface ToolDefinition {
  type: 'function';
  function: {
    name: string;
    description: string;
    parameters: Record<string, unknown>;
  };
}

// ============================================================================
// COMPLETION TYPES
// ============================================================================

/**
 * Completion request options
 */
export interface CompletionOptions {
  model?: string;
  maxTokens?: number;
  temperature?: number;
  topP?: number;
  topK?: number;
  stopSequences?: string[];
  presencePenalty?: number;
  frequencyPenalty?: number;
  tools?: ToolDefinition[];
  toolChoice?: 'auto' | 'none' | 'required' | { type: 'function'; function: { name: string } };
  responseFormat?: { type: 'text' | 'json_object' };
  seed?: number;
  user?: string;
}

/**
 * Completion response
 */
export interface CompletionResponse {
  id: string;
  model: string;
  content: string;
  finishReason: 'stop' | 'length' | 'tool_calls' | 'content_filter' | 'error';
  toolCalls?: ToolCall[];
  usage: TokenUsage;
  latencyMs: number;
}

/**
 * Token usage information
 */
export interface TokenUsage {
  promptTokens: number;
  completionTokens: number;
  totalTokens: number;
  cachedTokens?: number;
}

/**
 * Health check status
 */
export interface HealthStatus {
  healthy: boolean;
  latencyMs: number;
  message?: string;
  error?: Error;
}

/**
 * Streaming chunk
 */
export interface StreamChunk {
  id: string;
  model: string;
  delta: {
    content?: string;
    toolCalls?: Partial<ToolCall>[];
  };
  finishReason?: string;
}

// ============================================================================
// AI ADAPTER INTERFACE
// ============================================================================

/**
 * AI/LLM adapter interface
 * Abstracts away the specific AI provider implementation
 */
export interface AIAdapter {
  /**
   * Get provider name
   */
  getName(): string;

  /**
   * Get default model
   */
  getDefaultModel(): string;

  /**
   * List available models
   */
  listModels(): Promise<string[]>;

  /**
   * Check if provider is available
   */
  isAvailable(): Promise<boolean>;

  /**
   * Health check
   */
  healthCheck(): Promise<HealthStatus>;

  // -------------------------------------------------------------------------
  // Chat Completion
  // -------------------------------------------------------------------------

  /**
   * Generate chat completion
   */
  chat(
    messages: ChatMessage[],
    options?: CompletionOptions
  ): Promise<CompletionResponse>;

  /**
   * Generate chat completion with system prompt
   */
  chatWithSystem(
    systemPrompt: string,
    messages: ChatMessage[],
    options?: CompletionOptions
  ): Promise<CompletionResponse>;

  /**
   * Generate streaming chat completion
   */
  chatStream(
    messages: ChatMessage[],
    options?: CompletionOptions
  ): AsyncGenerator<StreamChunk, void, unknown>;

  /**
   * Generate streaming chat completion with system prompt
   */
  chatStreamWithSystem(
    systemPrompt: string,
    messages: ChatMessage[],
    options?: CompletionOptions
  ): AsyncGenerator<StreamChunk, void, unknown>;

  // -------------------------------------------------------------------------
  // Text Completion (simple)
  // -------------------------------------------------------------------------

  /**
   * Generate text completion (single turn)
   */
  complete(
    prompt: string,
    options?: CompletionOptions
  ): Promise<CompletionResponse>;

  /**
   * Generate streaming text completion
   */
  completeStream(
    prompt: string,
    options?: CompletionOptions
  ): AsyncGenerator<StreamChunk, void, unknown>;

  // -------------------------------------------------------------------------
  // Tool Calling
  // -------------------------------------------------------------------------

  /**
   * Chat with tool calling
   */
  chatWithTools(
    messages: ChatMessage[],
    tools: ToolDefinition[],
    options?: Omit<CompletionOptions, 'tools'>
  ): Promise<CompletionResponse>;

  /**
   * Process tool call results and continue conversation
   */
  continueWithToolResults(
    messages: ChatMessage[],
    toolResults: Array<{ toolCallId: string; result: string }>,
    tools: ToolDefinition[],
    options?: Omit<CompletionOptions, 'tools'>
  ): Promise<CompletionResponse>;

  // -------------------------------------------------------------------------
  // Utility
  // -------------------------------------------------------------------------

  /**
   * Count tokens in text
   */
  countTokens(text: string, model?: string): Promise<number>;

  /**
   * Get model context window size
   */
  getContextWindowSize(model?: string): number;

  /**
   * Get usage/rate limit status
   */
  getRateLimitStatus?(): Promise<{
    remainingRequests: number;
    remainingTokens: number;
    resetAt: Date;
  }>;
}

// ============================================================================
// AI SERVICE CONFIGURATION
// ============================================================================

/**
 * AI service configuration
 */
export interface AIServiceConfig {
  provider: string;
  apiKey?: string;
  baseUrl?: string;
  defaultModel?: string;
  timeout?: number;
  maxRetries?: number;
  defaultOptions?: Partial<CompletionOptions>;
}

/**
 * Multi-provider AI service
 */
export interface AIService {
  /**
   * Get adapter for specific provider
   */
  getAdapter(provider?: string): AIAdapter;

  /**
   * Get default adapter
   */
  getDefaultAdapter(): AIAdapter;

  /**
   * Set default provider
   */
  setDefaultProvider(provider: string): void;

  /**
   * Register a new adapter
   */
  registerAdapter(name: string, adapter: AIAdapter): void;

  /**
   * List available providers
   */
  listProviders(): string[];

  /**
   * Unified chat (uses default adapter)
   */
  chat(
    messages: ChatMessage[],
    options?: CompletionOptions & { provider?: string }
  ): Promise<CompletionResponse>;

  /**
   * Unified streaming chat
   */
  chatStream(
    messages: ChatMessage[],
    options?: CompletionOptions & { provider?: string }
  ): AsyncGenerator<StreamChunk, void, unknown>;
}

// ============================================================================
// PROMPT TEMPLATES
// ============================================================================

/**
 * Prompt template
 */
export interface PromptTemplate {
  id: string;
  name: string;
  description?: string;
  template: string;
  variables: string[];
  defaultValues?: Record<string, string>;
}

/**
 * Prompt template engine
 */
export interface PromptTemplateEngine {
  /**
   * Register a template
   */
  register(template: PromptTemplate): void;

  /**
   * Get template by ID
   */
  get(id: string): PromptTemplate | undefined;

  /**
   * Render template with variables
   */
  render(id: string, variables: Record<string, string>): string;

  /**
   * Render template string directly
   */
  renderString(template: string, variables: Record<string, string>): string;

  /**
   * List all templates
   */
  list(): PromptTemplate[];
}

// ============================================================================
// ZOD SCHEMAS
// ============================================================================

export const ChatMessageSchema = z.object({
  role: z.enum(['system', 'user', 'assistant', 'function', 'tool']),
  content: z.string(),
  name: z.string().optional(),
  toolCallId: z.string().optional(),
  toolCalls: z
    .array(
      z.object({
        id: z.string(),
        type: z.literal('function'),
        function: z.object({
          name: z.string(),
          arguments: z.string(),
        }),
      })
    )
    .optional(),
});

export const CompletionOptionsSchema = z.object({
  model: z.string().optional(),
  maxTokens: z.number().min(1).max(200000).optional(),
  temperature: z.number().min(0).max(2).optional(),
  topP: z.number().min(0).max(1).optional(),
  topK: z.number().min(1).optional(),
  stopSequences: z.array(z.string()).optional(),
  presencePenalty: z.number().min(-2).max(2).optional(),
  frequencyPenalty: z.number().min(-2).max(2).optional(),
  responseFormat: z
    .object({
      type: z.enum(['text', 'json_object']),
    })
    .optional(),
  seed: z.number().optional(),
  user: z.string().optional(),
});

export const ToolDefinitionSchema = z.object({
  type: z.literal('function'),
  function: z.object({
    name: z.string().min(1),
    description: z.string(),
    parameters: z.record(z.unknown()),
  }),
});

export const AIServiceConfigSchema = z.object({
  provider: z.string().min(1),
  apiKey: z.string().optional(),
  baseUrl: z.string().url().optional(),
  defaultModel: z.string().optional(),
  timeout: z.number().min(1000).max(600000).optional(),
  maxRetries: z.number().min(0).max(10).optional(),
  defaultOptions: CompletionOptionsSchema.optional(),
});
